{
  "name": "PHP Project Modernizer",
  "description": "An application that takes a zipped legacy PHP project, analyzes its structure, and suggests a modernized, more scalable file structure using AI."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback } from 'react';
import { FileNode } from './types';
import { modernizeStructure } from './services/geminiService';
import FileUpload from './components/FileUpload';
import FileTree from './components/FileTree';
import { ArrowRightIcon, LoaderIcon } from './components/Icons';

// This is to make JSZip available in the component since it's loaded from a CDN
declare const JSZip: any;

const App: React.FC = () => {
    const [zipFile, setZipFile] = useState<File | null>(null);
    const [oldFileTree, setOldFileTree] = useState<FileNode | null>(null);
    const [newFileTree, setNewFileTree] = useState<FileNode | null>(null);
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [error, setError] = useState<string | null>(null);

    const buildTreeFromPaths = (paths: string[]): FileNode => {
        const root: FileNode = { name: 'project_root', type: 'folder', children: [] };

        paths.forEach(path => {
            const parts = path.split('/').filter(p => p);
            let currentNode = root;

            parts.forEach((part, index) => {
                let childNode = currentNode.children?.find(child => child.name === part);

                if (!childNode) {
                    const isLastPart = index === parts.length - 1;
                    const type = isLastPart && path.includes('.') ? 'file' : 'folder';

                    childNode = { name: part, type };
                    if (type === 'folder') {
                        childNode.children = [];
                    }
                    currentNode.children?.push(childNode);
                }
                currentNode = childNode;
            });
        });

        // Sort children at each level
        const sortChildren = (node: FileNode) => {
            if (node.children) {
                node.children.sort((a, b) => {
                    if (a.type === 'folder' && b.type === 'file') return -1;
                    if (a.type === 'file' && b.type === 'folder') return 1;
                    return a.name.localeCompare(b.name);
                });
                node.children.forEach(sortChildren);
            }
        };

        sortChildren(root);
        return root;
    };

    const handleFileChange = useCallback(async (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file && file.type === 'application/zip') {
            setZipFile(file);
            setError(null);
            setNewFileTree(null);
            setIsLoading(true);
            try {
                const jszip = new JSZip();
                const zip = await jszip.loadAsync(file);
                const filePaths = Object.keys(zip.files).filter(path => !zip.files[path].dir);
                const tree = buildTreeFromPaths(filePaths);
                setOldFileTree(tree);
            } catch (err) {
                console.error("Error reading zip file:", err);
                setError('Failed to read the zip file. Please ensure it is a valid zip archive.');
                setOldFileTree(null);
            } finally {
                setIsLoading(false);
            }
        } else {
            setZipFile(null);
            setOldFileTree(null);
            setNewFileTree(null);
            setError('Please upload a valid .zip file.');
        }
    }, []);

    const handleModernize = useCallback(async () => {
        if (!oldFileTree) return;

        const getPaths = (node: FileNode, prefix = ''): string[] => {
            const currentPath = prefix ? `${prefix}/${node.name}` : node.name;
            if (node.type === 'file') {
                return [currentPath];
            }
            return node.children?.flatMap(child => getPaths(child, currentPath)) || [];
        };

        const paths = oldFileTree.children?.flatMap(child => getPaths(child)) || [];

        setIsLoading(true);
        setError(null);
        setNewFileTree(null);

        try {
            const result = await modernizeStructure(paths);
            setNewFileTree(result);
        } catch (err) {
            console.error("Error modernizing structure:", err);
            const errorMessage = err instanceof Error ? err.message : 'An unknown error occurred.';
            setError(`Failed to generate new structure. ${errorMessage}`);
        } finally {
            setIsLoading(false);
        }
    }, [oldFileTree]);

    return (
        <div className="min-h-screen bg-gray-900 text-gray-200 font-sans p-4 sm:p-6 lg:p-8">
            <div className="max-w-7xl mx-auto">
                <header className="text-center mb-8">
                    <h1 className="text-4xl sm:text-5xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-indigo-600">
                        Legacy PHP Project Modernizer
                    </h1>
                    <p className="mt-4 text-lg text-gray-400">
                        อัปโหลดโปรเจค PHP (.zip) ของคุณเพื่อรับโครงสร้างไฟล์ที่ทันสมัยซึ่งสร้างโดย AI
                    </p>
                </header>

                <main>
                    <div className="bg-gray-800/50 rounded-lg shadow-2xl p-6 mb-8 border border-gray-700 backdrop-blur-sm">
                        <FileUpload onChange={handleFileChange} disabled={isLoading} />
                        {error && <p className="text-red-400 mt-4 text-center">{error}</p>}
                    </div>

                    {oldFileTree && (
                        <div className="text-center mb-8">
                            <button
                                onClick={handleModernize}
                                disabled={isLoading}
                                className="px-8 py-3 bg-indigo-600 text-white font-semibold rounded-lg shadow-lg hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2 focus:ring-offset-gray-900 transition-all duration-300 disabled:bg-gray-600 disabled:cursor-not-allowed flex items-center justify-center mx-auto"
                            >
                                {isLoading ? (
                                    <>
                                        <LoaderIcon className="animate-spin mr-3" />
                                        Analyzing...
                                    </>
                                ) : (
                                    'Modernize Structure'
                                )}
                            </button>
                        </div>
                    )}

                    <div className="grid grid-cols-1 md:grid-cols-2 md:gap-8 items-start">
                        {oldFileTree && (
                            <div className="bg-gray-800/50 rounded-lg p-6 border border-gray-700 backdrop-blur-sm min-h-[300px]">
                                <h2 className="text-2xl font-bold mb-4 text-center text-gray-300">Current Structure</h2>
                                <FileTree root={oldFileTree} />
                            </div>
                        )}

                        {isLoading && !newFileTree && (
                             <div className="bg-gray-800/50 rounded-lg p-6 border border-gray-700 backdrop-blur-sm min-h-[300px] flex flex-col items-center justify-center mt-8 md:mt-0">
                                <LoaderIcon className="animate-spin h-12 w-12 text-indigo-400 mb-4" />
                                <h2 className="text-xl font-semibold text-gray-300">Generating new structure...</h2>
                                <p className="text-gray-400">AI is thinking, this might take a moment.</p>
                            </div>
                        )}

                        {newFileTree && (
                            <div className="relative bg-gray-800/50 rounded-lg p-6 border border-indigo-500/50 backdrop-blur-sm mt-8 md:mt-0 min-h-[300px]">
                                <div className="absolute top-1/2 -left-4 transform -translate-x-full -translate-y-1/2 hidden md:block">
                                    <ArrowRightIcon className="w-8 h-8 text-indigo-400" />
                                </div>
                                <h2 className="text-2xl font-bold mb-4 text-center text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-indigo-500">
                                    Modernized Structure
                                </h2>
                                <FileTree root={newFileTree} />
                            </div>
                        )}
                    </div>
                </main>
            </div>
        </div>
    );
};

export default App;

export interface FileNode {
    name: string;
    type: 'file' | 'folder';
    children?: FileNode[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { FileNode } from '../types';

if (!process.env.API_KEY) {
  // In a real app, you'd want to handle this more gracefully.
  // For this context, we assume the key is provided by the environment.
  console.warn("API_KEY environment variable not set. Using a placeholder.");
  process.env.API_KEY = "YOUR_API_KEY_HERE"; 
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const responseSchema = {
    type: Type.OBJECT,
    properties: {
        name: { type: Type.STRING, description: "The root directory name, e.g., 'modern_project_root'" },
        type: { type: Type.STRING, description: "Should always be 'folder'" },
        children: {
            type: Type.ARRAY,
            description: "An array of files and folders in the root directory.",
            items: {
                type: Type.OBJECT,
                properties: {
                    name: { type: Type.STRING, description: "The name of the file or folder." },
                    type: { type: Type.STRING, description: "Either 'file' or 'folder'." },
                    children: {
                        type: Type.ARRAY,
                        description: "An array of child files/folders. Only for 'folder' type.",
                        items: {
                            type: Type.OBJECT,
                            // This allows for recursive definition
                            properties: {
                                name: { type: Type.STRING },
                                type: { type: Type.STRING },
                                children: { type: Type.ARRAY, items: { type: Type.OBJECT } }
                            }
                        }
                    }
                }
            }
        }
    }
};


export const modernizeStructure = async (filePaths: string[]): Promise<FileNode> => {
    const fileListString = filePaths.join('\n');

    const prompt = `
        Analyze the following file list from a legacy PHP project and propose a modern, scalable, and maintainable folder structure.
        The new structure should follow modern web development best practices, such as MVC (Model-View-Controller), component-based architecture, or a similar logical separation of concerns.

        Guidelines:
        1.  Group files by feature or responsibility (e.g., 'src/controllers', 'src/models', 'src/views', 'src/services', 'src/components').
        2.  Create a public directory for assets (CSS, JS, images) and the main index.php entry point.
        3.  Suggest a configuration directory (e.g., 'config').
        4.  Include a 'vendor' directory for dependencies (simulating Composer).
        5.  The response MUST be a valid JSON object matching the provided schema.

        Legacy File List:
        ---
        ${fileListString}
        ---

        Generate the new structure as a JSON object representing the file tree. Each node should have a 'name' and a 'type' ('file' or 'folder'). Folders can have a 'children' array.
    `;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
            },
        });

        const jsonText = response.text;
        if (!jsonText) {
            throw new Error("API returned an empty response.");
        }

        // Sometimes the API might wrap the JSON in markdown, so we extract it.
        const cleanedJson = jsonText.replace(/^```json\s*|```\s*$/g, '').trim();

        const parsedResult = JSON.parse(cleanedJson);
        return parsedResult as FileNode;
    } catch (error) {
        console.error("Error calling Gemini API:", error);
        if (error instanceof SyntaxError) {
             throw new Error("Failed to parse the API response. The response was not valid JSON.");
        }
        throw new Error("An error occurred while communicating with the Gemini API.");
    }
};

