import React from 'react';
import { FileNode } from '../types';
import { FileIcon, FolderIcon, FolderOpenIcon } from './Icons';

interface TreeNodeProps {
    node: FileNode;
    level: number;
}

const TreeNode: React.FC<TreeNodeProps> = ({ node, level }) => {
    const [isOpen, setIsOpen] = React.useState(level < 2); // Auto-expand first few levels

    const isFolder = node.type === 'folder';

    const handleToggle = () => {
        if (isFolder) {
            setIsOpen(!isOpen);
        }
    };

    return (
        <div>
            <div
                className={`flex items-center p-1 rounded-md hover:bg-gray-700/50 transition-colors duration-200 ${isFolder ? 'cursor-pointer' : ''}`}
                style={{ paddingLeft: `${level * 20}px` }}
                onClick={handleToggle}
            >
                {isFolder ? (
                    isOpen ? <FolderOpenIcon className="mr-2 text-indigo-400" /> : <FolderIcon className="mr-2 text-indigo-400" />
                ) : (
                    <FileIcon className="mr-2 text-gray-500" />
                )}
                <span className="text-gray-300">{node.name}</span>
            </div>
            {isFolder && isOpen && node.children && (
                <div>
                    {node.children.map((child, index) => (
                        <TreeNode key={`${child.name}-${index}`} node={child} level={level + 1} />
                    ))}
                </div>
            )}
        </div>
    );
};

interface FileTreeProps {
    root: FileNode;
}

const FileTree: React.FC<FileTreeProps> = ({ root }) => {
    return (
        <div className="font-mono text-sm">
            {root.children?.map((node, index) => (
                <TreeNode key={`${node.name}-${index}`} node={node} level={0} />
            ))}
        </div>
    );
};

export default FileTree;

