import React from 'react';

// A simple placeholder chart component using CSS
export const SatisfactionChart: React.FC = () => {
    const dataPoints = [4.2, 4.5, 4.3, 4.6, 4.8, 4.7, 4.9];
    const maxVal = 5;
    const minVal = 4;

    const points = dataPoints.map((val, i) => {
      const x = (i / (dataPoints.length - 1)) * 100;
      const y = 100 - ((val - minVal) / (maxVal - minVal)) * 100;
      return `${x},${y}`;
    }).join(' ');

    return (
        <div className="h-64 w-full p-4 relative">
            <svg width="100%" height="100%" viewBox="0 0 100 100" preserveAspectRatio="none">
                {/* Grid Lines */}
                {[...Array(5)].map((_, i) => (
                     <line key={i} x1="0" y1={i * 25} x2="100" y2={i * 25} stroke="#e5e7eb" className="dark:stroke-gray-700" strokeWidth="0.5"/>
                ))}

                {/* Data line */}
                <polyline
                    fill="none"
                    stroke="#4f46e5"
                    strokeWidth="2"
                    points={points}
                />
            </svg>
            <div className="absolute bottom-0 left-0 w-full flex justify-between text-xs text-gray-500 dark:text-gray-400 px-2">
                <span>Sun</span>
                <span>Mon</span>
                <span>Tue</span>
                <span>Wed</span>
                <span>Thu</span>
                <span>Fri</span>
                <span>Sat</span>
            </div>
        </div>
    );
};

import React, { useState } from 'react';
import { Ticket, TicketStatus } from '../types';
import { SortIcon } from './Icons';

interface TicketsTableProps {
    tickets: Ticket[];
}

const statusColors: Record<TicketStatus, string> = {
    'Resolved': 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-300',
    'In Progress': 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-300',
    'Open': 'bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-300',
};

export const TicketsTable: React.FC<TicketsTableProps> = ({ tickets }) => {
    // Mock sorting state
    const [sortConfig, setSortConfig] = useState<{ key: keyof Ticket, direction: 'asc' | 'desc' } | null>(null);

    const handleSort = (key: keyof Ticket) => {
        let direction: 'asc' | 'desc' = 'asc';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
            direction = 'desc';
        }
        setSortConfig({ key, direction });
        // In a real app, you would sort the `tickets` array here.
    };

    const renderSortIcon = (key: keyof Ticket) => {
        if (!sortConfig || sortConfig.key !== key) {
            return <SortIcon className="w-4 h-4 text-gray-400" />;
        }
        return sortConfig.direction === 'asc' ? '▲' : '▼';
    };

    return (
        <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                <thead className="bg-gray-50 dark:bg-gray-700">
                    <tr>
                        {['customerName', 'issue', 'status', 'agent', 'date'].map((key) => (
                             <th key={key} scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider cursor-pointer" onClick={() => handleSort(key as keyof Ticket)}>
                                <span className="flex items-center">
                                    {key.replace(/([A-Z])/g, ' $1').replace(/^./, str => str.toUpperCase())}
                                    <span className="ml-2">{renderSortIcon(key as keyof Ticket)}</span>
                                </span>
                             </th>
                        ))}
                    </tr>
                </thead>
                <tbody className="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">
                    {tickets.map((ticket) => (
                        <tr key={ticket.id} className="hover:bg-gray-50 dark:hover:bg-gray-600/50 transition-colors">
                            <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900 dark:text-white">{ticket.customerName}</td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-300">{ticket.issue}</td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm">
                                <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${statusColors[ticket.status]}`}>
                                    {ticket.status}
                                </span>
                            </td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-300">{ticket.agent}</td>
                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-300">{ticket.date}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

