import React from 'react';
import { ArrowUpIcon, ArrowDownIcon } from './Icons';

interface KpiCardProps {
    title: string;
    value: string;
    trend: string;
    icon: React.ReactNode;
}

export const KpiCard: React.FC<KpiCardProps> = ({ title, value, trend, icon }) => {
    const isPositive = trend.startsWith('+');

    return (
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-6 flex items-center justify-between">
            <div>
                <p className="text-sm font-medium text-gray-500 dark:text-gray-400">{title}</p>
                <p className="text-3xl font-bold text-gray-900 dark:text-white mt-1">{value}</p>
                <div className={`flex items-center text-sm mt-2 ${isPositive ? 'text-green-500' : 'text-red-500'}`}>
                    {isPositive ? <ArrowUpIcon className="w-4 h-4 mr-1" /> : <ArrowDownIcon className="w-4 h-4 mr-1" />}
                    <span>{trend} จากสัปดาห์ที่แล้ว</span>
                </div>
            </div>
            <div className="bg-gray-100 dark:bg-gray-700 rounded-full p-3">
                {icon}
            </div>
        </div>
    );
};

