export const TicketsTable: React.FC<TicketsTableProps> = ({ tickets }) => {
    // Mock sorting state
    const [sortConfig, setSortConfig] = useState<{ key: keyof Ticket, direction: 'asc' | 'desc' } | null>(null);

    const handleSort = (key: keyof Ticket) => {
        let direction: 'asc' | 'desc' = 'asc';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
            direction = 'desc';
        }
        setSortConfig({ key, direction });
        // In a real app, you would sort the `tickets` array here.
    };

    const renderSortIcon = (key: keyof Ticket) => {
        if (!sortConfig || sortConfig.key !== key) {
            return <SortIcon className="w-4 h-4 text-gray-400" />;
        }
        return sortConfig.direction === 'asc' ? '▲' : '▼';
    };

    return (
        <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                <thead className="bg-gray-50 dark:bg-gray-700">
