            case 'notifications':
                 return <Notifications />;
            // Add cases for other views here, returning placeholder components
            case 'map':
            case 'users':
            case 'help':
            case 'settings':
                return <div className="p-8"><h1 className="text-2xl font-bold">หน้านี้อยู่ระหว่างการพัฒนา</h1></div>;
            case 'dashboard':
            default:
                return <Dashboard />;
        }
    };

    return (
        <div className="flex h-screen bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-200 font-sans">
            {isLoginModalOpen && <LoginModal onLoginSuccess={handleLoginSuccess} onClose={() => setIsLoginModalOpen(false)} />}

            <Sidebar currentView={currentView} setCurrentView={setCurrentView} />

            <div className="flex-1 flex flex-col overflow-hidden">
                <header className="bg-white dark:bg-gray-800 shadow-sm p-4 flex justify-between items-center">
                    <div className="flex items-center">
                         {/* Placeholder for menu toggle on mobile */}
                    </div>
                    <div className="text-sm">
                        {isLoggedIn ? (
                             <div className="flex items-center space-x-4">
                                <span className="flex items-center">
                                    <UserCircleIcon className="w-6 h-6 mr-2 text-green-500" />
                                    ยินดีต้อนรับ, ผู้ดูแลระบบ
                                </span>
                                <button onClick={handleLogout} className="flex items-center text-red-500 hover:text-red-700 dark:hover:text-red-400 font-semibold">
                                    <LogoutIcon className="w-5 h-5 mr-1" />
                                    ออกจากระบบ
                                </button>
                             </div>
                        ) : (
                            <button onClick={() => setIsLoginModalOpen(true)} className="flex items-center bg-blue-600 text-white px-4 py-2 rounded-md hover:bg-blue-700 transition-colors shadow">
                                <LoginIcon className="w-5 h-5 mr-2" />
                                เข้าสู่ระบบ
                            </button>
                        )}
                    </div>
                </header>

                <main className="flex-1 overflow-x-hidden overflow-y-auto bg-gray-100 dark:bg-gray-900 p-4 sm:p-6 lg:p-8">
                    {renderView()}
                </main>
            </div>
        </div>
    );
};

