const App: React.FC = () => {
    const [isLoggedIn, setIsLoggedIn] = useState(false);
    const [isLoginModalOpen, setIsLoginModalOpen] = useState(false);
    const [currentView, setCurrentView] = useState('dashboard');

    const handleLoginSuccess = () => {
        setIsLoggedIn(true);
        setIsLoginModalOpen(false);
    };

    const handleLogout = () => {
        setIsLoggedIn(false);
    };

    const renderView = () => {
        switch (currentView) {
            case 'survey-forms':
                return <SurveyForm />;
            case 'customers':
                return <CustomerManagement />;
            case 'reports':
                return <AnalyticsReports />;
            case 'users':
                return <UserManagement />;
            case 'help':
                return <HelpCenter />;
            case 'settings':
                return <Settings />;
            case 'dashboard':
            default:
                return <Dashboard />;
        }
    };

    return (
        <div className="flex h-screen bg-gray-900 text-gray-200">
            {isLoginModalOpen && <LoginModal onLoginSuccess={handleLoginSuccess} onClose={() => setIsLoginModalOpen(false)} />}

            <Sidebar currentView={currentView} setCurrentView={setCurrentView} isLoggedIn={isLoggedIn} />

            <div className="flex-1 flex flex-col overflow-hidden">
                <header className="bg-gray-800 shadow-sm p-4 flex justify-between items-center">
                    <div className="flex items-center">
                         {/* Placeholder for menu toggle on mobile */}
                    </div>
                    <div className="text-sm">
                        {isLoggedIn ? (
                             <div className="flex items-center space-x-4">
                                <span className="flex items-center">
                                    <UserCircleIcon className="w-6 h-6 mr-2 text-green-500" />
                                    ยินดีต้อนรับ, ผู้ดูแลระบบ
                                </span>
                                <button onClick={handleLogout} className="flex items-center text-red-500 hover:text-red-400 font-semibold">
                                    <LogoutIcon className="w-5 h-5 mr-1" />
                                    ออกจากระบบ
                                </button>
                             </div>
                        ) : (
                            <button onClick={() => setIsLoginModalOpen(true)} className="flex items-center bg-blue-600 text-white px-4 py-2 rounded-md hover:bg-blue-700 transition-colors shadow">
                                <LoginIcon className="w-5 h-5 mr-2" />
                                เข้าสู่ระบบ
                            </button>
                        )}
                    </div>
                </header>

                <main className="flex-1 overflow-x-hidden overflow-y-auto bg-gray-900 p-4 sm:p-6 lg:p-8">
                    {renderView()}
                </main>
            </div>
        </div>
    );
};

